#pragma GCC optimize("O3,unroll-loops")
#pragma GCC target("avx2,bmi,bmi2,lzcnt,popcnt")
#include <vector>
#include <algorithm>

void adaptive_sort(std::vector<int>& v) {
    int n = v.size(), i = 1;
    if (n < 2) return;
    while (i < n && v[i] <= v[i-1]) ++i;
    if (v[0] > v[i-1]) std::reverse(v.begin(), v.begin() + i);
    while (i < n && v[i-1] <= v[i]) ++i;
    if (i == n) return;
    int mn = v[0], mx = mn;
    for (int x : v) mn = std::min(mn, x), mx = std::max(mx, x);
    long long r = (long long)mx - mn;
    if (r < 2000000 && r < n * 32LL) {
        std::vector<int> c(r + 1, 0);
        for (int x : v) c[x - mn]++;
        auto it = v.begin();
        for (int j = 0; j <= (int)r; ++j)
            if (int k = c[j]) it = std::fill_n(it, k, j + mn);
        return;
    }
    if (i * 4 > n || n - i < 80) {
        std::sort(v.begin() + i, v.end());
        if (v[i] < v[i-1]) std::inplace_merge(v.begin(), v.begin() + i, v.end());
    } else std::sort(v.begin(), v.end());
}

